/// Abhinav7-4-2026 
/// Auto post intercompany sales order 
public static void autoPostIntercompanySalesOrder(SalesTable salesTableLoc)
{
    if(salesTableLoc.InterCompanyOrder)
    {
        if(salesTableLoc.DefaultDimension)
        {
            boolean                     isValid = true;
            boolean                     isValidLine;
            DimensionValidationStatus   dimensionValidationStatus;
            DimensionValidationStatus   dimensionValidationStatusLine;
            LedgerDimensionAccount      ledgerDimension;
            CustPostingProfile          postingprofile = salesTableLoc.PostingProfile ? salesTableLoc.PostingProfile : CustParameters::find().PostingProfile;

            ledgerDimension = LedgerDimensionFacade::serviceCreateLedgerDimension(CustLedgerAccounts::summaryLedgerDimension(salesTableLoc.CustAccount,postingprofile,true),salesTableLoc.DefaultDimension);
            dimensionValidationStatus = LedgerDimensionValidationHelper::validateByTree(ledgerDimension, salesTableLoc.DeliveryDate, true, true);

            if(dimensionValidationStatus == DimensionValidationStatus::Valid)
            {
                SalesLine SalesLine;

                while select SalesLine
                    where SalesLine.salesid == salesTableLoc.SalesId
                {
                    ledgerDimension = LedgerDimensionFacade::serviceCreateLedgerDimension(CustLedgerAccounts::summaryLedgerDimension(SalesLine.CustAccount,postingprofile,true),SalesLine.DefaultDimension);
                    dimensionValidationStatusLine = LedgerDimensionValidationHelper::validateByTree(ledgerDimension, salesTableLoc.DeliveryDate, true, true);

                    if(dimensionValidationStatusLine == DimensionValidationStatus::Valid)
                    {
                        isValidLine = true;
                    }
                    else
                    {
                        isValidLine = false;
                        break;
                    }
                }
            }
            else
            {
                isValid = false;
            }


            if(isValid && isValidLine)
            {
                SalesFormLetter_PackingSlip  salesFormLetterPackingSlip;
                SalesFormLetter_Invoice  salesFormLetterInvoice;

                if (SalesLine::exist(salesTableLoc.SalesId))
                {
                    try
                    {
                        ttsBegin;
                        salesFormLetterPackingSlip = SalesFormLetter::construct(DocumentStatus::PackingSlip);

                        salesFormLetterPackingSlip.update(salesTableLoc,
                                        DateTimeUtil::getSystemDate(DateTimeUtil::getUserPreferredTimeZone()),
                                        SalesUpdate::All,
                                        AccountOrder::None,
                                        NoYes::No,
                                        NoYes::No );
                        ttsCommit;
                    }
                    catch
                    {
                        warning("@ETG_New:SalesOrderPackingSlipPostingError");
                    }

                    if (salesTableLoc && salesTableLoc.SalesStatus != SalesStatus::Invoiced)
                    {
                        try
                        {
                            ttsBegin;
                            salesFormLetterInvoice = SalesFormLetter::construct(DocumentStatus::Invoice);

                            salesFormLetterInvoice.update(salesTableLoc,
                                        DateTimeUtil::getSystemDate(DateTimeUtil::getUserPreferredTimeZone()),
                                        SalesUpdate::PackingSlip,
                                        AccountOrder::None,
                                        NoYes::No,
                                        NoYes::No );

                            ttsCommit;
                        }
                        catch
                        {
                            warning("@ETG_New:SalesOrderInvoicePostingError");
                        }
                    }
                }
            }
            else
            {
                warning("@ETG_New:MandatoryFDValuesSO");
            }
        }
        else
        {
            warning("@ETG_New:MandatoryFDValuesNotAvailable");
        }

    }
}
